import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-ChtuvW5g.js";var s={class:`ant-doc vp-doc`},c=a({__name:`secondary-development.en-US`,setup(a,{expose:c}){let l={title:`Secondary Development`,frontmatter:{title:`Secondary Development`},headers:[{level:2,title:`Template Repository`,slug:`template-repository`,link:`#template-repository`,children:[]},{level:2,title:`When to use it`,slug:`when-to-use-it`,link:`#when-to-use-it`,children:[]},{level:2,title:`What is included`,slug:`what-is-included`,link:`#what-is-included`,children:[]},{level:2,title:`One thing to do before you start`,slug:`one-thing-to-do-before-you-start`,link:`#one-thing-to-do-before-you-start`,children:[]},{level:2,title:`Quick Start`,slug:`quick-start`,link:`#quick-start`,children:[{level:3,title:`1. Clone the template`,slug:`_1-clone-the-template`,link:`#_1-clone-the-template`,children:[]},{level:3,title:`2. Install dependencies`,slug:`_2-install-dependencies`,link:`#_2-install-dependencies`,children:[]},{level:3,title:`3. Run the docs app`,slug:`_3-run-the-docs-app`,link:`#_3-run-the-docs-app`,children:[]},{level:3,title:`4. Build the library`,slug:`_4-build-the-library`,link:`#_4-build-the-library`,children:[]}]},{level:2,title:`Recommended Workflow`,slug:`recommended-workflow`,link:`#recommended-workflow`,children:[{level:3,title:`1. Rename the package and publishing metadata`,slug:`_1-rename-the-package-and-publishing-metadata`,link:`#_1-rename-the-package-and-publishing-metadata`,children:[]},{level:3,title:`2. Build your business components`,slug:`_2-build-your-business-components`,link:`#_2-build-your-business-components`,children:[]},{level:3,title:`3. Write documentation pages`,slug:`_3-write-documentation-pages`,link:`#_3-write-documentation-pages`,children:[]},{level:3,title:`4. Add demos next to docs pages`,slug:`_4-add-demos-next-to-docs-pages`,link:`#_4-add-demos-next-to-docs-pages`,children:[]}]},{level:2,title:`Project Structure`,slug:`project-structure`,link:`#project-structure`,children:[]},{level:2,title:`Theme Notes`,slug:`theme-notes`,link:`#theme-notes`,children:[]},{level:2,title:`Who this template is for`,slug:`who-this-template-is-for`,link:`#who-this-template-is-for`,children:[]}],description:``},u={title:`Secondary Development`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>If you want to build your own business component library, documentation site, and demo system on top of <code>antdv-next</code>, we provide a ready-to-use starter repository: <a href="https://github.com/antdv-next/docs-base">docs-base</a>.</p><p>This template is more than a basic scaffold. It combines component source code, documentation pages, a Markdown demo pipeline, and library build outputs in one project, making it suitable for teams that want to evolve and publish internal or public component libraries continuously.</p><h2 id="template-repository" tabindex="-1">Template Repository <a class="header-anchor" href="#template-repository" aria-label="Permalink to &quot;Template Repository&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/antdv-next/docs-base">https://github.com/antdv-next/docs-base</a></li><li>Chinese README: <a href="https://github.com/antdv-next/docs-base/blob/main/README.zh-CN.md">README.zh-CN.md</a></li><li>English README: <a href="https://github.com/antdv-next/docs-base/blob/main/README.md">README.md</a></li></ul><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Use this template when you want to:</p><ul><li>build a business-oriented component library based on <code>antdv-next</code></li><li>keep component source, demos, and documentation in one place</li><li>ship typed Vue 3 components</li><li>write docs in Markdown while embedding real Vue demos</li><li>maintain Chinese and English docs with the same structure</li><li>create your own theme system instead of inheriting a fixed visual style</li></ul><h2 id="what-is-included" tabindex="-1">What is included <a class="header-anchor" href="#what-is-included" aria-label="Permalink to &quot;What is included&quot;">​</a></h2><ul><li>Vue 3 + TypeScript + Vite</li><li><code>antdv-next</code> as the UI foundation</li><li>preserved module output, bundled ESM, and UMD builds</li><li>generated type declarations</li><li>a custom Markdown-to-Vue docs pipeline</li><li>live demo rendering, source extraction, and hot updates</li><li>UnoCSS, Vue Router, Pinia, and Vue I18n integration</li><li>sample components and documentation pages that you can extend directly</li></ul><h2 id="one-thing-to-do-before-you-start" tabindex="-1">One thing to do before you start <a class="header-anchor" href="#one-thing-to-do-before-you-start" aria-label="Permalink to &quot;One thing to do before you start&quot;">​</a></h2><p>The template uses <code>@org/components</code> as a placeholder package name. Before secondary development, do a global search and replace for <code>@org/components</code> and switch it to your actual package name.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><h3 id="_1-clone-the-template" tabindex="-1">1. Clone the template <a class="header-anchor" href="#_1-clone-the-template" aria-label="Permalink to &quot;1. Clone the template&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">git</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> clone</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> https://github.com/antdv-next/docs-base.git</span></span>
<span class="line"><span style="--ant-doc-light:#998418;--ant-doc-dark:#B8A965;">cd</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs-base</span></span></code></pre></div><h3 id="_2-install-dependencies" tabindex="-1">2. Install dependencies <a class="header-anchor" href="#_2-install-dependencies" aria-label="Permalink to &quot;2. Install dependencies&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> install</span></span></code></pre></div><h3 id="_3-run-the-docs-app" tabindex="-1">3. Run the docs app <a class="header-anchor" href="#_3-run-the-docs-app" aria-label="Permalink to &quot;3. Run the docs app&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs:dev</span></span></code></pre></div><p>The local development site runs at <a href="http://localhost:6878">http://localhost:6878</a> by default.</p><h3 id="_4-build-the-library" tabindex="-1">4. Build the library <a class="header-anchor" href="#_4-build-the-library" aria-label="Permalink to &quot;4. Build the library&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> build</span></span></code></pre></div><p>Other useful commands:</p><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs:build</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs:preview</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> type-check</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> test:unit</span></span></code></pre></div><h2 id="recommended-workflow" tabindex="-1">Recommended Workflow <a class="header-anchor" href="#recommended-workflow" aria-label="Permalink to &quot;Recommended Workflow&quot;">​</a></h2><h3 id="_1-rename-the-package-and-publishing-metadata" tabindex="-1">1. Rename the package and publishing metadata <a class="header-anchor" href="#_1-rename-the-package-and-publishing-metadata" aria-label="Permalink to &quot;1. Rename the package and publishing metadata&quot;">​</a></h3><ul><li>replace <code>@org/components</code> globally</li><li>update the package name and publish metadata in <code>package.json</code></li></ul><h3 id="_2-build-your-business-components" tabindex="-1">2. Build your business components <a class="header-anchor" href="#_2-build-your-business-components" aria-label="Permalink to &quot;2. Build your business components&quot;">​</a></h3><p>Create or adapt components under <code>components/</code>, and export them from <code>components/index.ts</code> so the public API stays explicit and stable.</p><h3 id="_3-write-documentation-pages" tabindex="-1">3. Write documentation pages <a class="header-anchor" href="#_3-write-documentation-pages" aria-label="Permalink to &quot;3. Write documentation pages&quot;">​</a></h3><p>Add Markdown pages under <code>docs/src/pages/</code>. The template auto-registers <code>.md</code> files as routes through <code>import.meta.glob</code>.</p><p>Recommended locale naming:</p><ul><li><code>*.zh-CN.md</code></li><li><code>*.en-US.md</code></li></ul><h3 id="_4-add-demos-next-to-docs-pages" tabindex="-1">4. Add demos next to docs pages <a class="header-anchor" href="#_4-add-demos-next-to-docs-pages" aria-label="Permalink to &quot;4. Add demos next to docs pages&quot;">​</a></h3><p>Place demo files in a sibling <code>demo/</code> directory and reference them like this:</p><div class="language-md ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#393A34;--ant-doc-dark:#DBD7CAEE;">&lt;demo-group&gt;</span></span>
<span class="line"><span style="--ant-doc-light:#393A34;--ant-doc-dark:#DBD7CAEE;">  &lt;demo src=&quot;./demo/basic.vue&quot;&gt;Basic example&lt;/demo&gt;</span></span>
<span class="line"><span style="--ant-doc-light:#393A34;--ant-doc-dark:#DBD7CAEE;">&lt;/demo-group&gt;</span></span></code></pre></div><p>The docs pipeline will automatically:</p><ul><li>render the live Vue demo</li><li>extract the source code</li><li>generate highlighted code blocks</li><li>hot-update demo metadata during development</li></ul><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><div class="language-text ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>.</span></span>
<span class="line"><span>├─ components/                 # Business component source</span></span>
<span class="line"><span>├─ docs/                       # Documentation app</span></span>
<span class="line"><span>│  ├─ src/pages/               # Markdown pages and home page</span></span>
<span class="line"><span>│  ├─ src/components/demo/     # Demo renderer and source viewer</span></span>
<span class="line"><span>│  └─ plugins/markdown/        # Markdown / demo transform pipeline</span></span>
<span class="line"><span>├─ vite.build.config.ts        # Preserve-module build</span></span>
<span class="line"><span>├─ vite.esm.config.ts          # Bundled ESM build</span></span>
<span class="line"><span>├─ vite.umd.config.ts          # UMD build</span></span>
<span class="line"><span>└─ global.d.ts                 # Global component typings</span></span></code></pre></div><h2 id="theme-notes" tabindex="-1">Theme Notes <a class="header-anchor" href="#theme-notes" aria-label="Permalink to &quot;Theme Notes&quot;">​</a></h2><p>The template is intentionally theme-neutral. You can build your own brand style, design tokens, and component appearance on top of it. For the theming side, see <a href="/docs/vue/customize-theme">Customize Theme</a>.</p><h2 id="who-this-template-is-for" tabindex="-1">Who this template is for <a class="header-anchor" href="#who-this-template-is-for" aria-label="Permalink to &quot;Who this template is for&quot;">​</a></h2><p>If you do not want to maintain demos in a separate repo and prefer to keep:</p><ul><li>component implementation</li><li>documentation pages</li><li>live examples</li><li>multilingual content</li><li>build outputs</li></ul><p>in a single codebase, <code>docs-base</code> is a practical starting point.</p>`,45)]]))}});export{c as default};